643 static SmallBitVector buildUseMask(int VF, ArrayRef<int> Mask,
644                                    UseMask MaskArg) {
645   SmallBitVector UseMask(VF, true);
646   for (auto [Idx, Value] : enumerate(Mask)) {
647     if (Value == PoisonMaskElem) {
648       if (MaskArg == UseMask::UndefsAsMask)
