660 /// Checks if the given value is actually an undefined constant vector.
661 /// Also, if the \p UseMask is not empty, tries to check if the non-masked
662 /// elements actually mask the insertelement buildvector, if any.
663 template <bool IsPoisonOnly = false>
664 static SmallBitVector isUndefVector(const Value *V,
665                                     const SmallBitVector &UseMask = {}) {
666   SmallBitVector Res(UseMask.empty() ? 1 : UseMask.size(), true);
667   using T = std::conditional_t<IsPoisonOnly, PoisonValue, UndefValue>;
668   if (isa<T>(V))
669     return Res;
670   auto *VecTy = dyn_cast<FixedVectorType>(V->getType());
671   if (!VecTy)
672     return Res.reset();
673   auto *C = dyn_cast<Constant>(V);
674   if (!C) {
675     if (!UseMask.empty()) {
676       const Value *Base = V;
677       while (auto *II = dyn_cast<InsertElementInst>(Base)) {
678         Base = II->getOperand(0);
679         if (isa<T>(II->getOperand(1)))
680           continue;
681         std::optional<unsigned> Idx = getElementIndex(II);
682         if (!Idx) {
683           Res.reset();
684           return Res;
685         }
686         if (*Idx < UseMask.size() && !UseMask.test(*Idx))
687           Res.reset(*Idx);
688       }
689       // TODO: Add analysis for shuffles here too.
690       if (V == Base) {
691         Res.reset();
692       } else {
693         SmallBitVector SubMask(UseMask.size(), false);
694         Res &= isUndefVector<IsPoisonOnly>(Base, SubMask);
695       }
696     } else {
697       Res.reset();
698     }
699     return Res;
700   }
701   for (unsigned I = 0, E = VecTy->getNumElements(); I != E; ++I) {
702     if (Constant *Elem = C->getAggregateElement(I))
703       if (!isa<T>(Elem) &&
704           (UseMask.empty() || (I < UseMask.size() && !UseMask.test(I))))
705         Res.reset(I);
706   }
707   return Res;
708 }
