770     auto *Vec = EI->getVectorOperand();
771     // We can extractelement from undef or poison vector.
772     if (isUndefVector</*isPoisonOnly=*/true>(Vec).all())
773       continue;
774     // All vector operands must have the same number of vector elements.
775     if (isa<UndefValue>(Vec)) {
776       Mask[I] = I;
777     } else {
778       if (isa<UndefValue>(EI->getIndexOperand()))
779         continue;
780       auto *Idx = dyn_cast<ConstantInt>(EI->getIndexOperand());
781       if (!Idx)
782         return std::nullopt;
783       // Undefined behavior if Idx is negative or >= Size.
784       if (Idx->getValue().uge(Size))
