786       unsigned IntIdx = Idx->getValue().getZExtValue();
787       Mask[I] = IntIdx;
788     }
789     if (isUndefVector(Vec).all() && HasNonUndefVec)
790       continue;
791     // For correct shuffling we have to have at most 2 different vector operands
792     // in all extractelement instructions.
793     if (!Vec1 || Vec1 == Vec) {
794       Vec1 = Vec;
795     } else if (!Vec2 || Vec2 == Vec) {
796       Vec2 = Vec;
797       Mask[I] += Size;
798     } else {
799       return std::nullopt;
800     }
801     if (CommonShuffleMode == Permute)
802       continue;
803     // If the extract index is not the same as the operation number, it is a
804     // permutation.
805     if (Mask[I] % Size != I) {
806       CommonShuffleMode = Permute;
807       continue;
808     }
809     CommonShuffleMode = Select;
810   }
811   // If we're not crossing lanes in different vectors, consider it as blending.
812   if (CommonShuffleMode == Select && Vec2)
813     return TargetTransformInfo::SK_Select;
814   // If Vec2 was never used, we have a permutation of a single vector, otherwise
815   // we have permutation of 2 vectors.
