 855   /// Sort SupportedOp because it is used by binary_search.
 856   constexpr static std::initializer_list<unsigned> SupportedOp = {
 857       Instruction::Add,  Instruction::Sub, Instruction::Mul, Instruction::Shl,
 858       Instruction::AShr, Instruction::And, Instruction::Or,  Instruction::Xor};
 859   enum : MaskType {
 860     ShlBIT = 0b1,
 861     AShrBIT = 0b10,
 862     MulBIT = 0b100,
 863     AddBIT = 0b1000,
 864     SubBIT = 0b10000,
 865     AndBIT = 0b100000,
 866     OrBIT = 0b1000000,
 867     XorBIT = 0b10000000,
 868     MainOpBIT = 0b100000000,
 869     LLVM_MARK_AS_BITMASK_ENUM(MainOpBIT)
 870   };
 871   /// Return a non-nullptr if either operand of I is a ConstantInt.
 872   /// The second return value represents the operand position. We check the
 873   /// right-hand side first (1). If the right hand side is not a ConstantInt and
