 924       if (Candidate & AShrBIT)
 925         return Instruction::AShr;
 926       if (Candidate & MulBIT)
 927         return Instruction::Mul;
 928       if (Candidate & AddBIT)
 929         return Instruction::Add;
 930       if (Candidate & SubBIT)
 931         return Instruction::Sub;
 932       if (Candidate & AndBIT)
 933         return Instruction::And;
 934       if (Candidate & OrBIT)
 935         return Instruction::Or;
 936       if (Candidate & XorBIT)
 937         return Instruction::Xor;
 938       llvm_unreachable("Cannot find interchangeable instruction.");
