 940     SmallVector<Value *> getOperand(const Instruction *To) const {
 941       unsigned ToOpcode = To->getOpcode();
 942       unsigned FromOpcode = I->getOpcode();
 943       if (FromOpcode == ToOpcode)
 944         return SmallVector<Value *>(I->operands());
 945       assert(binary_search(SupportedOp, ToOpcode) && "Unsupported opcode.");
 946       auto [CI, Pos] = isBinOpWithConstantInt(I);
 947       const APInt &FromCIValue = CI->getValue();
 948       unsigned FromCIValueBitWidth = FromCIValue.getBitWidth();
 949       APInt ToCIValue;
 950       switch (FromOpcode) {
 951       case Instruction::Shl:
 952         if (ToOpcode == Instruction::Mul) {
 953           ToCIValue = APInt::getOneBitSet(FromCIValueBitWidth,
 954                                           FromCIValue.getZExtValue());
 955         } else {
 956           assert(FromCIValue.isZero() && "Cannot convert the instruction.");
 957           ToCIValue = ToOpcode == Instruction::And
 958                           ? APInt::getAllOnes(FromCIValueBitWidth)
 959                           : APInt::getZero(FromCIValueBitWidth);
 960         }
 961         break;
 962       case Instruction::Mul:
 963         assert(FromCIValue.isPowerOf2() && "Cannot convert the instruction.");
 964         if (ToOpcode == Instruction::Shl) {
 965           ToCIValue = APInt(FromCIValueBitWidth, FromCIValue.logBase2());
 966         } else {
 967           assert(FromCIValue.isOne() && "Cannot convert the instruction.");
 968           ToCIValue = ToOpcode == Instruction::And
 969                           ? APInt::getAllOnes(FromCIValueBitWidth)
 970                           : APInt::getZero(FromCIValueBitWidth);
 971         }
 972         break;
 973       case Instruction::Add:
 974       case Instruction::Sub:
 975         if (FromCIValue.isZero()) {
 976           ToCIValue = APInt::getZero(FromCIValueBitWidth);
 977         } else {
 978           assert(is_contained({Instruction::Add, Instruction::Sub}, ToOpcode) &&
 979                  "Cannot convert the instruction.");
 980           ToCIValue = FromCIValue;
 981           ToCIValue.negate();
 982         }
 983         break;
 984       case Instruction::And:
 985         assert(FromCIValue.isAllOnes() && "Cannot convert the instruction.");
 986         ToCIValue = ToOpcode == Instruction::Mul
 987                         ? APInt::getOneBitSet(FromCIValueBitWidth, 0)
 988                         : APInt::getZero(FromCIValueBitWidth);
 989         break;
 990       default:
 991         assert(FromCIValue.isZero() && "Cannot convert the instruction.");
 992         ToCIValue = APInt::getZero(FromCIValueBitWidth);
 993         break;
 994       }
 995       Value *LHS = I->getOperand(1 - Pos);
 996       Constant *RHS =
 997           ConstantInt::get(I->getOperand(Pos)->getType(), ToCIValue);
