1021       : MainOp(MainOp), AltOp(AltOp) {
1022     assert(is_sorted(SupportedOp) && "SupportedOp is not sorted.");
1023   }
1024   bool add(const Instruction *I) {
1025     assert(isa<BinaryOperator>(I) &&
1026            "BinOpSameOpcodeHelper only accepts BinaryOperator.");
1027     unsigned Opcode = I->getOpcode();
1028     MaskType OpcodeInMaskForm;
1029     // Prefer Shl, AShr, Mul, Add, Sub, And, Or and Xor over MainOp.
1030     switch (Opcode) {
1031     case Instruction::Shl:
1032       OpcodeInMaskForm = ShlBIT;
1033       break;
1034     case Instruction::AShr:
1035       OpcodeInMaskForm = AShrBIT;
1036       break;
1037     case Instruction::Mul:
1038       OpcodeInMaskForm = MulBIT;
1039       break;
1040     case Instruction::Add:
1041       OpcodeInMaskForm = AddBIT;
1042       break;
1043     case Instruction::Sub:
1044       OpcodeInMaskForm = SubBIT;
1045       break;
1046     case Instruction::And:
1047       OpcodeInMaskForm = AndBIT;
1048       break;
1049     case Instruction::Or:
1050       OpcodeInMaskForm = OrBIT;
1051       break;
1052     case Instruction::Xor:
1053       OpcodeInMaskForm = XorBIT;
1054       break;
1055     default:
1056       return MainOp.equal(Opcode) ||
1057              (initializeAltOp(I) && AltOp.equal(Opcode));
1058     }
1059     MaskType InterchangeableMask = OpcodeInMaskForm;
1060     ConstantInt *CI = isBinOpWithConstantInt(I).first;
1061     if (CI) {
1062       constexpr MaskType CanBeAll =
1063           XorBIT | OrBIT | AndBIT | SubBIT | AddBIT | MulBIT | AShrBIT | ShlBIT;
1064       const APInt &CIValue = CI->getValue();
1065       switch (Opcode) {
1066       case Instruction::Shl:
1067         InterchangeableMask = CIValue.isZero() ? CanBeAll : MulBIT | ShlBIT;
1068         break;
1069       case Instruction::Mul:
1070         if (CIValue.isOne()) {
1071           InterchangeableMask = CanBeAll;
1072           break;
1073         }
1074         if (CIValue.isPowerOf2())
1075           InterchangeableMask = MulBIT | ShlBIT;
1076         break;
1077       case Instruction::Add:
1078       case Instruction::Sub:
1079         InterchangeableMask = CIValue.isZero() ? CanBeAll : SubBIT | AddBIT;
1080         break;
1081       case Instruction::And:
1082         if (CIValue.isAllOnes())
1083           InterchangeableMask = CanBeAll;
1084         break;
1085       default:
1086         if (CIValue.isZero())
1087           InterchangeableMask = CanBeAll;
1088         break;
1089       }
1090     }
1091     return MainOp.trySet(OpcodeInMaskForm, InterchangeableMask) ||
1092            (initializeAltOp(I) &&
1093             AltOp.trySet(OpcodeInMaskForm, InterchangeableMask));
